🏆leetcode 记录leetcode中的题目🤡 在此文件中更新🧐
134.加油站 将每个站点进行处理，得到从当前站点至下个站点能够剩余的汽油，可以将此看为一个最长连续子序列的变形。 只要能够找到从一个点出发，一直相加使得和不为0，这样就满足题目所给出的条件。因为还可能存在不满足的情况，所以最后还需要再判断一下。
class Solution { public: int canCompleteCircuit(vector&lt;int&gt;&amp; gas, vector&lt;int&gt;&amp; cost) { int len = gas.size(); int start = 0; int MAX = 0; int now = 0; for (int i = 0; i &lt; len; i++) { now += (gas[i] - cost[i]); if (now &lt; 0) { now = 0; start = i + 1; } if (now &gt; MAX) { MAX = now; } } MAX = 0; for (int i = start; i &lt; len; i++) { MAX += gas[i] - cost[i]; if (MAX &lt; 0) return -1; } for (int i = 0; i &lt; start; i++) { MAX += gas[i] - cost[i]; if (MAX &lt; 0) return -1; } return start; } }; 452. 用最少数量的箭引爆气球 dp做法，复杂度n2 将气球按照l,r升序排序，处理从每个气球出发，能够最多引爆多少气球，可以得到一组数列，数列中a[i] 代码从i出发走一步能够跨越的最大距离，对数列进行处理，就可以得到到达最后一个气球所花费最小的步数。
class Solution {public: int findMinArrowShots(vector&lt;vector&lt;int&gt;&gt;&amp; points) { sort(points.begin(), points.end(), [](const vector&lt;int&gt;&amp; a, const vector&lt;int&gt;&amp; b) { if (a[0] == b[0]) return a[1] &lt; b[1]; else return a[0] &lt; b[0]; }); int len = points.size(); //cout &lt;&lt; &#34;len &#34; &lt;&lt; len &lt;&lt; endl; vector&lt;int&gt; l; for (int i = 0; i &lt; len; i++) { int s = points[i][0]; int e = points[i][1]; int num = 1; for (int j = i + 1; j &lt; len; j++) { if (points[j][0] &lt;= e) { s = max(s, points[j][0]); e = min(e, points[j][1]); num++; } else { break; } } //cout &lt;&lt; &#34;l &#34; &lt;&lt; num &lt;&lt; endl; l.push_back(num); } vector&lt;int&gt; ans(len + 1, 99999); ans[0] = 0; //cout &lt;&lt; &#34;ans size &#34; &lt;&lt; ans.size() &lt;&lt; endl; for (int i = 0; i &lt; len; i++) { for (int j = 1; j &lt;= l[i]; j++) { ans[i + j] = min(ans[i + j], ans[i] + 1); } } return ans[len]; } }; 贪心做法，复杂度nlog 将气球按照r升序排序，从第一个气球出发，气球引爆范围包括r的就可以引爆，然后对升序的气球做同样的处理。
class Solution { public: int findMinArrowShots(vector&lt;vector&lt;int&gt;&gt;&amp; points) { sort(points.begin(), points.end(), [](const vector&lt;int&gt;&amp; a, const vector&lt;int&gt;&amp; b) { return a[1] &lt; b[1]; }); int len = points.size(); int ans = 0; for (int i = 0; i &lt; len; i++) { ans++; int now = points[i][1]; while(i &lt; len &amp;&amp; points[i][0] &lt;= now) { i++; } i--; } return ans; } }; 222. 完全二叉树的节点个数 二分查找
/** * Definition for a binary tree node. * struct TreeNode { * int val; * TreeNode *left; * TreeNode *right; * TreeNode(int x) : val(x), left(NULL), right(NULL) {} * }; */class Solution {public: int countNodes(TreeNode* root) { int h = 0; TreeNode* tmp = root; while(tmp != nullptr) { h++; tmp = tmp -&gt; left; } int ans = pow(2, h - 1) - 1; tmp = root; for (int i = 1; i &lt;= h; i++) { TreeNode* p = tmp; if (tmp != nullptr) if (f(p, h - i)) { tmp = tmp -&gt; right; ans += pow(2, h - 1 - i) + 0.5; } else { tmp = tmp -&gt; left; } } return ans; } bool f(TreeNode* tmp, int h) { if (h == 0) { return tmp != nullptr; } tmp = tmp -&gt; right; for (int i = 1; i &lt; h; i++) { tmp = tmp -&gt; left; } return tmp != nullptr; } }; 暴力递归
/** * Definition for a binary tree node. * struct TreeNode { * int val; * TreeNode *left; * TreeNode *right; * TreeNode(int x) : val(x), left(NULL), right(NULL) {} * }; */ class Solution { public: int countNodes(TreeNode* root) { if (root == nullptr) { return 0; } return countNodes(root -&gt; left) + countNodes(root -&gt; right) + 1; } }; 1370. 上升下降字符串 统计每个字符出现的次数，然后从头到尾，从尾到头扫描，直至所有字符都被输出
class Solution { public: string sortString(string s) { vector&lt;int&gt; v(26,0); int len = s.length(); for (int i = 0; i &lt; len; i++) { v[s[i] - &#39;a&#39;]++; } string ans = &#34;&#34;; while(len) { for (int i = 0; i &lt; 26; i++) { if (v[i] &gt; 0) { v[i]--; ans += char(&#39;a&#39; + i); len--; } } for (int i = 25; i &gt;= 0; i--) { if (v[i] &gt; 0) { v[i]--; ans += char(&#39;a&#39; + i); len--; } } } return ans; } }; 164. 最大间距 暴力排序，然后遍历(nlogn)
将数组划分为不同的区间，每块区间的长度为（MAX - MIN)/(n - 1）,然后遍历相邻的区间，用后面区间的最小值 - 前面区间的最大值，最终ans为所有差中的最大值
class Solution { public: int maximumGap(vector&amp; nums) { int len = nums.size(); if (len &lt; 2) return 0; int Max = *max_element(nums.begin(), nums.end()); int Min = *min_element(nums.begin(), nums.end()); int d = max(1, (Max - Min) / (len - 1)); int bucketSize = (Max - Min) / d + 1; vector&lt;pair&lt;long long, long long&raquo; v(bucketSize, {999999999, -1}); for (int i = 0; i &lt; len; i++) { int index = (nums[i] - Min) / d; v[index].first = min(v[index].first, nums[i] * 1ll); v[index].second = max(v[index].second, nums[i] * 1ll); } long long ans = 0; int pre = -1; for (int i = 0; i &lt; bucketSize; i++) { if (v[i].second == -1) continue; if (pre != -1 ) { ans = max(ans, v[i].first - v[pre].second); } pre = i; } return ans; } };
# [454. 四数相加 II](https://leetcode-cn.com/problems/4sum-ii/) 1.将AB，CD分别处理成两个单独的vector，然后排序，转换为两数相加 class Solution { public: int fourSumCount(vector&amp; A, vector&amp; B, vector&amp; C, vector&amp; D) { int len = A.size(); vector a; vector b; for (int i = 0; i &lt; len; i++) { for (int j = 0; j &lt; len; j++) { a.push_back(A[i] + B[j]); b.push_back(C[i] + D[j]); } } sort(a.begin(), a.end()); sort(b.begin(), b.end());
len = a.size(); //cout &lt;&lt; &quot;len &quot; &lt;&lt; len &lt;&lt; endl; int s = 0; int e = len - 1; int ans = 0; while(s &lt; len || e &gt;= 0) { //cout &lt;&lt; &quot;s &quot; &lt;&lt; s &lt;&lt; &quot; e &quot; &lt;&lt; e &lt;&lt; endl; int now = a[s] + b[e]; if (now == 0) { int tmp = a[s]; int l1 = 0, l2 = 0; while(s &lt; len &amp;&amp; a[s] == tmp) { s++; l1++; } tmp = b[e]; while(e &gt;= 0 &amp;&amp; b[e] == tmp) { e--; l2++; } ans += l1 * l2; } else if(now &lt; 0) { s++; } else { e--; } //cout &lt;&lt; &quot;ans1 &quot; &lt;&lt; ans &lt;&lt; endl; if (s == len) { while(e &gt;= 0) { now = a[len - 1] + b[e]; if (now == 0) { ans++; e--; } if (now &lt; 0) { break; } } break; } if (e &lt; 0) { while(s &lt; len) { now = a[s] + b[0]; if (now == 0) { ans++; s++; } if (now &gt; 0) { break; } } break; } } return ans; } };
2.对AB，CD分别进行处理，存在map中 class Solution { public: int fourSumCount(vector&amp; A, vector&amp; B, vector&amp; C, vector&amp; D) { unordered_map&lt;int, int&gt; countAB; for (int&amp; u: A) { for (int&amp; v: B) { countAB[u + v]++; } } int ans = 0; for (int&amp; u: C) { for (int&amp; v: D) { if (countAB.count(-u - v)) { ans += countAB[-u - v]; } } } return ans; } };
# [5615. 使数组互补的最少操作次数](https://leetcode-cn.com/problems/minimum-moves-to-make-array-complementary/) 首先很容易想到的一个点是去遍历所有的可能[2, 2 * limit],然后去判断每一对的和为X时，最少的操作次数为多少。 对于每一对数的和变为X需要的操作次数，取一对数中较小的数为a, 较大的数为b，再加上a+b, 我们可以得到5个点，分别为2, a + 1, a + b, b + limit, 2 * limit。 X的取值范围 与 一对数的和变为X的关系为: [2, a + 1) : 2 [a, a + b) : 1 [a + b, a + b] : 0 [a + b + 1, b + limit] : 1 [b + limit + 1, 2 * limit) : 2 所以当确定X之后，我们便能很快的求得一对数的和变为X的操作数。 如果暴力遍历[2, 2 * limit]去判断的话，复杂度为O(n2)，很明显会超时。 下面就是如何在一部分去优化复杂度。 这里可以类比题目[452. 用最少数量的箭引爆气球](https://leetcode-cn.com/problems/minimum-number-of-arrows-to-burst-balloons/)，我们是可以得到最终的结果一定是不会是一个区间的中间值，一定是所有的（a, a + b, a + b + 1, b + limit + 1）中存在的，所以我们可以将搜索范围缩小至所有的（a, a + b, a + b + 1, b + limit + 1）中。 但是所有的（a, a + b, a + b + 1, b + limit + 1）中的个数是有可能与2 * limit相近的，直接去遍历所有出现过的点，复杂度没有降下来。 下面我们去判断针对一对数的情况，在不同的区间，一对数的和变为X的操作数k是怎么变化的，我们参考上面提到的 **X的取值范围 与 一对数的和变为X的关系** 设X的取值开始为2，k也为2 然后增大为a时，k为1 然后增大为a + b时， k为0 然后增大为a + b + 1时， k为1 然后增大为b + limit + 1时，k为2 对于一组数我们可以得到这样的变化特性，我们可以将多对数的这些数字叠加起来，将**迭代判断转化为线性变化扫描**，这样将复杂度降到O(n) class Solution { public: int minMoves(vector&amp; nums, int limit) { int len = nums.size(); map&lt;int, int&gt; m; for (int i = 0; i &lt; len / 2; i++) { int Min = min(nums[i], nums[len - 1 - i]); int Max = max(nums[i], nums[len - 1 - i]); int l = Min + 1; int r = Max + limit; int sum = nums[i] + nums[len - 1 - i]; m[l]&ndash;; m[sum]&ndash;; m[sum + 1]++; m[r + 1]++; } int ans = 999999; int now = len; for (auto &amp;s : m) { now += s.second; ans = min(ans, now); } return ans; } };
# [1673. 找出最具竞争力的子序列](https://leetcode-cn.com/problems/find-the-most-competitive-subsequence/) 最容易想到的一种方法是，在[0,len-k+1)个数中找到最小的（设最小的数下标为l1），然后即为ans的第一个数，然后从[l1 + 1, len-k + 2)中找到最小的，然后依次循环，直到找到k个数。 这样复杂度为O(n2) 可以使用单调栈来优化复杂度，首先对前len-k+1个数进行处理，得到单调递增的栈，然后再依次处理剩下的k-1个数，注意最终单调栈中的数字个数必须大于等于k 在此代码中利用双向队列去实现单调栈 class Solution { public: vector mostCompetitive(vector&amp; nums, int k) { deque v; int len = nums.size(); for (int i = 0; i &lt; len - k + 1; i++) { while (!v.empty() &amp;&amp; nums[i] &lt; v.back()) { v.pop_back(); } v.push_back(nums[i]); }
vector&lt;int&gt; ans; int lsum = v.size() - 1; for (int i = len - k + 1; i &lt; len; i++) { while(lsum &gt; 0 &amp;&amp; nums[i] &lt; v.back()) { v.pop_back(); lsum--; } v.push_back(nums[i]); } for (int i = 0; i &lt; k; i++) { ans.push_back(v[i]); } return ans; } };
# 842. 将数组拆分成斐波那契序列 因为数据最长只有200，又因为数字的范围在int范围内，所以我们可以暴力一点。 用循环来枚举出数列的前两项，然然后再依次判断是否可以构成数列。 ```class Solution { public: vector&lt;int&gt; splitIntoFibonacci(string S) { int len = S.length(); vector&lt;int&gt; ans; if (len &lt; 3) return vector&lt;int&gt;(0); for (int i = 1; i &lt; len - 2 &amp;&amp; i &lt; 12; i++) { for (int j = i + 1; j &lt; len - 1 &amp;&amp; j - i &lt; 12; j++) { ans.clear(); string s1 = S.substr(0, i); string s2 = S.substr(i, j - i); long long num1 = b(s1); long long num2 = b(s2); //cout &lt;&lt; &#34;num1 &#34; &lt;&lt; num1 &lt;&lt; &#34; num2 &#34; &lt;&lt; num2 &lt;&lt; endl; if (num1 == -1 || num2 == -1) { continue; } ans.push_back((int)num1); ans.push_back((int)num2); bool flag = true; int now = j; while(now &lt; len &amp;&amp; flag) { long long num3 = num1 + num2; //cout &lt;&lt; &#34;num3 &#34; &lt;&lt; num3 &lt;&lt; endl; if (num3 &gt;= (1ll&lt;&lt;32)) { flag = false; break; } int ll = l(num3); //cout &lt;&lt; &#34;l num3 &#34; &lt;&lt; num3 &lt;&lt; endl; if (now + ll - 1 &gt;= len) { flag = false; break; } string s3 = S.substr(now, ll); if (b(s3) != num3) { flag = false; break; } ans.push_back((int)num3); num1 = num2; num2 = num3; now = now + ll; } if (!flag) { continue; } if (now &gt;= len) { return ans; } } } return vector&lt;int&gt;(0); } long long f(string&amp; s) { long long ans = 0; for (auto c : s) { ans = ans * 10 + int(c - &#39;0&#39;); } return ans; } long long b(string&amp; s) { int len = s.length(); if (len &gt; 1 &amp;&amp; s[0] == &#39;0&#39;) { return -1; } long long tmp = f(s); if (tmp &gt;= 0 &amp;&amp; tmp &lt;= (1ll&lt;&lt;32 - 1)) { return tmp; } else { return -1; } } int l(long long x) { if(x == 0) return 1; int ans = 0; while(x) { ans++; x /= 10; } return ans; } }; 649. Dota2 参议院 用list处理一下就行，之前很少用到list，这次熟悉了一次。
public: string predictPartyVictory(string senate) { int suma = 0; int sumb = 0; string aa = &#34;Radiant&#34;; string bb = &#34;Dire&#34;; list&lt;char&gt; l; for (auto c : senate) { if (c == &#39;R&#39;) { suma++; } else { sumb++; } l.push_back(c); } int a = 0, b = 0; int nowa = 0, nowb = 0; while(nowa &lt; suma &amp;&amp; nowb &lt; sumb) { for(auto it = l.begin(); it != l.end(); it++) { //cout &lt;&lt; *it &lt;&lt; endl; if (*it == &#39;R&#39;) { if (a &gt; 0) { it = l.erase(it); it--; nowa++; a--; } else { b++; } } else { if (b &gt; 0) { it = l.erase(it); it--; nowb++; b--; } else { a++; } } } } if(nowa == suma) { return bb; } else { return aa; } } }; 376. 摆动序列 构建状态转移方程式，二维的dp数组，dp[i][0]代表i之前的最后为升序的最长长度，dp[i][1]代表i之前的最后为降序的最长长度。 最后也可以减少空间复杂度
class Solution { public: int wiggleMaxLength(vector&lt;int&gt;&amp; nums) { if (nums.size() == 0) return 0; int up = 1; int down = 1; for (int i = 1; i &lt; nums.size(); i++) { if (nums[i] &gt; nums[i - 1]) { up = max(down + 1, up); } else if (nums[i] &lt; nums[i - 1]) { down = max(up + 1, down); } } return max(up, down); } };

题目： 司令部的将军们打算在N*N的网格地图上部署他们的炮兵部队。一个N*N的地图由N行N列组成，地图的每一格可能是山地（用&quot;X&quot;表示），也可能是平原（用&quot;.&ldquo;表示）。在每一格平原地形上最多可以布置一支炮兵部队（山地上不能够部署炮兵部队）；一支炮兵部队在地图上的攻击范围是它所在位置的对应的行和列，但是大炮打出去之后如果被山地阻挡 了，那么攻击范围就到那块山地。
现在，将军们规划如何部署炮兵部队，在防止误伤的前提下（保证任何两支炮兵部队之间不能互相攻击，即任何一支炮兵部队都不在其他支炮兵部队的攻击范围内），在整个地图区域内最多能够摆放多少我军的炮兵部队。
样例解释：
上图中显示的是相同的地图中不同的放置大炮的方案。黑方块表示山地，白方块表示平原，黑圆表示对应的平原放置了大炮。第一张图是不放大炮的情况。第二张图和第三张图是合理的放置大炮的方案。最后两张图是不合理的放置大炮的方案。 对于这个地图来讲，最多能放置5门大炮。第二张图就是一种最优的放置方案，当然还有其它的最优放置方案。
输入 单组测试数据。 第一行有一个整数N(1&lt;=N&lt;=4)。 接下来N行，每行有N个字符（只有两种字符：&rsquo;.&rsquo; 表示平原， &lsquo;X&rsquo;表示山地）。 输出 输出一个整数表示答案。 输入样例 样例输入1 4 .X.. &hellip;. XX.. &hellip;. 输出样例 样例输出1 5 解法：因此数据极小，因此暴力每次情况即可，最终选取可放置数量最多的。 代码：
#include&lt;stdio.h&gt; #include&lt;algorithm&gt; using namespace std; int n; char c[5][5]; char s[5][5]; void change(int x) { for(int i = 0; i &lt; n; i++) for(int j = 0; j &lt; n; j++){ if(c[i][j] == &#39;.&#39;){ if(x&amp;1) s[i][j] = &#39;p&#39;; else{ s[i][j] = &#39;.&#39;; } } else{ s[i][j] = &#39;X&#39;; } x &gt;&gt;= 1; } } bool isTrue() { for(int i = 0; i &lt; n ;i++) { int now = 0; for(int j = 0; j &lt; n; j++){ if(s[i][j] == &#39;p&#39;) now++; else if(s[i][j] == &#39;X&#39;){ now = 0; } if(now &gt; 1) return false; } } for(int i = 0; i &lt; n ;i++) { int now = 0; for(int j = 0; j &lt; n; j++){ if(s[j][i] == &#39;p&#39;) now++; else if(s[j][i] == &#39;X&#39;){ now = 0; } if(now &gt; 1) return false; } } return true; } int ans() { int num = 0; for(int i = 0; i &lt; n; i++) for(int j = 0; j &lt; n; j++) if(s[i][j] == &#39;p&#39;) num++; return num; } int main() { scanf(&#34;%d\n&#34;, &amp;n); char t; for(int i = 0; i &lt; n ;i++){ for(int j = 0; j &lt; n; j++) scanf(&#34;%c&#34;, &amp;c[i][j]); scanf(&#34;%c&#34;, &amp;t); } int now = 1; now &lt;&lt;= n*n+1; now--; //printf(&#34;%d\n&#34;, now); int ANS = 0; while(now--) { change(now); if(isTrue()){ ANS = max(ANS, ans()); } } printf(&#34;%d\n&#34;, ANS); return 0; }

题目： 现在要在办公室里面安装监控， 由于预算有限，现在只能安装一个摄像头，这个摄像头是可以360度旋转的。现在就要选择一个位置安装这个摄像头，使得它能够监控到办公室中的所有地方。办公室的边界以多边形给出，这个多边的所有边都是平行于座标轴的，并且不自交。
样例解释：
左边的图对应的是第一个样例，把摄像头安装在点的位置就可以监控到所有的地方了，右边的图对应第二个样例，这个办公室没有办法找到一个地方安装摄像头使得所有地方都被监控到，如果安装在点的位置，灰色的部分就不能被监控到了。
输入 单组测试数据。 第一行有一个整数n (4 &lt;= n &lt;= 100)，表示多边形的顶点数目。 接下来n行，每行出两个整数x 和 y（-100000&lt;=x,y&lt;=100000），表示多边形的顶点，以顺时针的方向给出。 所有的顶点都是不一样的。 输出 如果能够安装一个摄像头使得所有区域被监控到输出Yes，否则输出No。 输入样例 样例输入1 4 0 0 0 1 1 1 1 0
样例输入2 8 0 0 0 2 1 2 1 1 2 1 2 2 3 2 3 0 输出样例 样例输出1 Yes 样例输出2 No 解法： 循环每条线段得到最终满足条件区域，最后判断区域是否为空即可 代码：
#include&lt;algorithm&gt; using namespace std; const int inf = 99999999; int main() { int n; scanf(&#34;%d&#34;, &amp;n); n--; int X,Y; scanf(&#34;%d%d&#34;, &amp;X, &amp;Y); int px = X, py = Y; int lx = -inf,rx = inf, ly = -inf, ry = inf; while(n--) { int x,y; scanf(&#34;%d%d&#34;, &amp;x, &amp;y); if(y &lt; Y) rx= min(rx, X); if(y &gt; Y) lx = max(lx, X); if(x &gt; X) ry = min(ry, Y); if(x &lt; X) ly = max(ly, Y); X = x; Y = y; } if(py &lt; Y) rx= min(rx, X); if(py &gt; Y) lx = max(lx, X); if(px &gt; X) ry = min(ry, Y); if(px &lt; X) ly = max(ly, Y); //printf(&#34;%d %d %d %d\n&#34;, lx, rx, ly, ry); if(ly &gt; ry || lx &gt; rx) printf(&#34;No&#34;); else { printf(&#34;Yes&#34;); } return 0; }

题目: 在网络中，发送一个包需要知道对方的物理地址，当不知道物理地趣的时候，就要向网络中广播发送对方的IP地址，然后每一台计算会收到这个广播，如果IP和自己的计算对上，就把自己的物理地址发送出去。 现在有n台计算，编号从1到n，现在1号计算向网络中发送广播，问经过多少时间后所有的计算机都会收到这个广播。
输入的网络保证所有的计算机之间是可以相互通信的。
输入 单组测试数据。 第一行有一个整数n(1 &lt;= n &lt;= 100)。 接下来输入一个邻接矩阵A，A的大小是n x n。里面的元素要么是一个非负整数，或者是一个字符x。如果A[i][j]是x那么第i台计算机和第j台计算机没有直接相连。否则表示信号在第i台计算机和第j台计算机之间传播需要A[i][j]的时间。 自己发给自己是不需要时间的所以对于所有的 1 &lt;= i &lt;= n，A[i][i] = 0。输入的网络是一个无向图，所以A[i][j] = A[j][i]。那么只需要输入矩阵的下三角部分即可。 那么接下来给出n-1行， 第一行有一个整数表示A[2][1]。 第二行有两个整数表示A[3][1]和A[3][2]。 。。。 第n-1行有n-1个整数A[n][1],A[n][2], A[n][3]&hellip; A[n][n-1]。 0&lt;=A[i][j]&lt;=100。 输出 输出一个整数表示答案。 输入样例 样例输入1 5 50 30 5 100 20 50 10 x x 10 输出样例 样例输出1 35 解法：最短路裸题 代码：
#include&lt;stdio.h&gt; #include&lt;iostream&gt; #include&lt;algorithm&gt; #include &lt;cstdlib&gt; #include&lt;string&gt; #include&lt;cmath&gt; #include&lt;queue&gt; #include&lt;vector&gt; using namespace std; struct Node { int to; long long len; bool operator&lt;(const Node &amp;a) const { return len &gt; a.len; } }; bool isUsed[510]; long long ans[510]; vector&lt;Node&gt; NodeQueue[510]; void addEdge(int s, int e, int len) { NodeQueue[s].push_back((Node){e,len}); NodeQueue[e].push_back((Node){s,len}); } int n; priority_queue&lt;Node&gt; PriNodeQueue; int main() { scanf(&#34;%d&#34;, &amp;n); for(int i = 2; i &lt;= n; i++) for(int j = 1; j &lt; i; j++){ string s; cin &gt;&gt; s; if(s != &#34;x&#34;){ int len = atoi(s.c_str()); //printf(&#34;%d\n&#34;, len); addEdge(i,j,len); } } for(int i = 0; i &lt; 505; i++) ans[i] = 999999999999; ans[1] = 0; PriNodeQueue.push((Node){1,0}); while(!PriNodeQueue.empty()){ Node now = PriNodeQueue.top(); PriNodeQueue.pop(); int u = now.to; if(!isUsed[u]){ isUsed[u] = true; for(int i = 0; i &lt; NodeQueue[u].size(); i++){ if(!isUsed[NodeQueue[u][i].to]){ int v = NodeQueue[u][i].to; int len = NodeQueue[u][i].len; if(ans[v] &gt; ans[u] + len) { ans[v] = ans[u] + len; PriNodeQueue.push((Node){v,ans[v]}); } } } } } long long a = 0; for(int i = 1; i &lt;= n; i++){ //printf(&#34;%d\n&#34;, ans[i]); a = max(a, ans[i]); } printf(&#34;%lld&#34;, a); return 0; }

题目： 问题描述 面对夜市上琳琅满目的美食, 吃货 Alice 正在犯难. 夜市上有 n 种食物. 每种都是不可分割地一份一份出售的. Alice 是一个珍惜食物的好孩子(吃货), 所以买到的食物她都会吃完不浪费. Alice 当然想尝试尽量多不同的的美味, 所以同一种食物她不会重复购买, 即最多只会买一份. 每份食物都有一个营养价值和美味指数. Alice当然想吃得又健康又美味, 所以她今晚的目标就是所吃食物的营养价值总和不能少于x, 而美味指数总和不能少于y. 精明的 Alice 当然想省下钱来明天再吃一顿, 所以她想花最少的钱实现她的目标.
所以 Alice 来求助同班的天才程序员 Bob, 就是你啦. 她告诉你 n 种食物的营养价值, 美味指数和价格, 以及她的目标 x 和 y. 你要告诉她最少要花多少钱才能达到目标.
输入 从标准文件输入, 第一行包括两个整数x和y, 由一个空格隔开(1&lt;=x&lt;=21,1&lt;=y&lt;=79)，表示 Alice 今晚的营养目标和美味目标。第二行包括一个整数n(1&lt;=n&lt;=1000)表示可选择的食物数量. 以下n行包括每种食物的描述：第i+2行包括三个整数xi、yi、pi,(1&lt;=xi&lt;=21,1&lt;=yi&lt;=79,1&lt;=pi&lt;=800)，分别为该种食物的营养价值, 美味指数和价格.
输出 你的程序应该输出一个整数，表示所选食物的最小总价格, 且其营养价值总和不小于x, 美味指数总和不小于y.
输入样例 5 60 5 3 36 120 10 25 129 5 50 250 1 45 130 4 20 119 输出样例 249 题解：01背包的变形，dp[i][j]代表营养价值为i，美味指数为j时的最小价格，因为必须满足营养价值与美味指数的要求，因此在状态转移时，dp[i][j]必须是有实际意义的值，因为x&lt;=21 y&lt;=79，因此dp数组的大小最多为dp[221][279],循环得到dp的值之后，选取最优的解即可。 代码：
#include&lt;algorithm&gt; using namespace std; int dp[55][205]; int xi[1010]; int yi[1010]; int pi[1010]; int main() { int x,y; scanf(&#34;%d%d&#34;, &amp;x, &amp;y); int n; scanf(&#34;%d&#34;, &amp;n); for(int i = 0; i &lt; n; i++) { scanf(&#34;%d%d%d&#34;, &amp;xi[i], &amp;yi[i], &amp;pi[i]); } for(int i = 0; i &lt; 50; i++) for(int j = 0; j &lt; 200; j++) dp[i][j] = 99999999; dp[0][0] = 0; for(int i = 0; i &lt; n; i++){ for(int x = 50; x - xi[i] &gt;= 0; x--){ for(int y = 200; y - yi[i] &gt;= 0; y--){ if(dp[x-xi[i]][y-yi[i]] != 99999999){ dp[x][y] = min(dp[x][y], dp[x-xi[i]][y-yi[i]] + pi[i]); } } } } int ans = 99999999; for(int i = x; i &lt; 50; i++) for(int j = y; j &lt; 200; j++) ans = min(ans, dp[i][j]); printf(&#34;%d\n&#34;, ans); }

给定一个字符串S，只由k种小写字母组成。现在给定一个长度L，要求统计一下S有多少种不同的长度为L的子段(S中连续的几个字符)。
输入 单组测试数据。 第一行两个整数L和k。（L&gt;=1，1&lt;=k&lt;=26,k^L&lt;=2*10^7） 第二行一个字符串S。（1&lt;=|S|&lt;=1000000） 输出 输出一个整数表示答案。
输入样例 1 2 ababab 输出样例 2 解法：暴力即可 代码：
#include&lt;iostream&gt; #include&lt;string&gt; #include&lt;set&gt; using namespace std; set&lt;string&gt; S; int main() { int l, k; scanf(&#34;%d%d&#34;, &amp;l, &amp;k); string s; cin &gt;&gt; s; for(int i = 0; i &lt;= s.length() - l; i++){ string s1 = s.substr(i, l); S.insert(s1); } printf(&#34;%lld\n&#34;, S.size()); }

题目： 现在大多数的文本编辑器都的单词究错功能，即你输入的单词不能够在词典中找到的话，他就会建议你修改，然后给出几个候选项。
现在我们就要来写一个生成候选项的算法。
具体算法是这样的，如果输入的单词能够在字典中找到，那么就不用推荐，否则就在字典中找那些能够通过修改一个字母得到目标单词的选项作为推荐。
修改一个字母包括删除一个字母，添加一个字母，以及把单词中的某个位置的字母进行替换。
输入 单组测试数据。 前面若干行给出字典中的单词，每行一个，遇到&quot;#&ldquo;表示字典中的单词输入结束。 接下来若干行给出用户输入的单词，每行一个，遇到&rdquo;#&ldquo;结束。 字典中单词不超过15000个。用户输入的单词不超过60个。每个单词只由小写字母组成，并且非空，长度不超过20。 输出 对于每一个用户的输入，如果在字典中能够找到就输出 &ldquo;单词 is correct&rdquo;。否则就输出&quot;单词: 候选1 候选2 &hellip;&quot;,候选项按照输入的顺序进行排列。如果找不到候选项，则输出&quot;单词:”。具体可参见样例。 输入样例 样例输入1 i has be more me if ^# me m contest oo i ^# 输出样例 样例输出1 me is correct m: i me contest: oo: i is correct 解法: 关键在于如何进行单词匹配，长度相差大于1的可以直接判断为false，长度相差为1的进行处理时，当出现字符不匹配时，选择进行一次删除或者添加操作(效果相同)，长度相同时直接一次判断即可。 代码：
#include&lt;iostream&gt; #include&lt;algorithm&gt; #include&lt;string&gt; #include&lt;set&gt; using namespace std; set&lt;string&gt; dict; set&lt;string&gt; words; string s[15010]; bool isTrue(string a, string b) { int la = a.length(), lb = b.length(); if(abs(la - lb) &gt; 1) return false; if(la == lb){ int sum = 0; for(int i = 0; i &lt; la; i++){ if(a[i] != b[i]) sum++; if(sum &gt; 1) return false; } } else{ int sum = 0; if(lb &gt; la) swap(a, b); int i = 0 ,j = 0; for(int k = 0; k &lt; lb; k++) { if(a[i++] != b[j++]){ sum++; if(sum == 2) return false; j--;lb++; } } } return true; } int main() { int now = 0 ,sum = 0; string str; while(cin&gt;&gt;str) { if(str == &#34;#&#34;){ now++; if(now == 2) break; continue; } if(now == 0){ dict.insert(str); s[sum++] = str; } else{ if(dict.find(str) != dict.end()){ cout &lt;&lt; str; printf(&#34; is correct\n&#34;); } else{ cout &lt;&lt; str &lt;&lt; &#34;:&#34;; for(int i = 0; i &lt; sum; i++){ if(isTrue(str,s[i])) cout&lt;&lt;&#34; &#34;&lt;&lt; s[i]; } cout&lt;&lt;endl; } } } }

题目： 你在一个二维空间里的(𝑥𝑀𝑒,𝑦𝑀𝑒)位置，你的家在(𝑥𝐻𝑜𝑚𝑒,𝑦𝐻𝑜𝑚𝑒)位置。每一秒钟你可以选择从你当前位置向上下左右四个方向之一移动一个单位。你现在归心似箭，觉得这么走很慢，所幸你有技能“凌波微步”，在这片二维空间中，有3对传送门，每一对传送门以(𝑥𝑠,𝑦𝑠,𝑥𝑡,𝑦𝑡)的形式给出，表示你到达(𝑥𝑠,𝑦𝑠)点就可以发动“凌波微步”技能，花费10秒钟到达(𝑥𝑡,𝑦𝑡)点，相反你也可以花费10秒钟从(𝑥𝑡,𝑦𝑡)点发动“凌波微步”技能到达(𝑥𝑠,𝑦𝑠)点。“凌波微步”技能可以无限多次发动，但只能在所给出的3对传送门之间使用。请问你回家最短用时多少秒。
输入 输入第一行4个整数，依次是xMe、yMe、xHome、yHome，表示当前你的位置和你家的位置。 接下来三行，每行描述一对传送门(xs, ys, xt, yt)，含义见题面（0 &lt;= xi, yi &lt;= 10^9） 输出 输出仅一行，包含一个整数表示回家的最少用时 输入样例 0 0 20 20 1 1 18 20 1000 1003 1000 1004 1000 1005 1000 1006 输出样例 14 解法: 最短路径的一个变形，就坐标映射为点就可以 代码:
#include&lt;algorithm&gt; #include&lt;cmath&gt; #include&lt;queue&gt; #include&lt;vector&gt; #include&lt;map&gt; using namespace std; struct Node { int to; long long len; bool operator&lt;(const Node &amp;a) const { return len &gt; a.len; } }; struct xy { int x; int y; bool operator&lt;(const xy &amp;a) const { if(x == a.x) return y &lt; a.y; else { return x &lt; a.x; } } }; bool isUsed[510]; long long ans[510]; vector&lt;Node&gt; NodeQueue[510]; void addEdge(int s, int e, int len) { NodeQueue[s].push_back((Node){e,len}); NodeQueue[e].push_back((Node){s,len}); } map&lt;xy,int&gt; m; priority_queue&lt;Node&gt; PriNodeQueue; int main() { int sum = 0; int xme, yme, xhome, yhome; scanf(&#34;%d%d%d%d&#34;, &amp;xme, &amp;yme, &amp;xhome, &amp;yhome); m[(xy){xme,yme}] = sum++; m[(xy){xhome,yhome}] = sum++; addEdge(0,1,abs(xme-xhome) + abs(yme - yhome)); for(int i = 1; i &lt; 4; i++) { int x1,y1,x2,y2; scanf(&#34;%d%d%d%d&#34;, &amp;x1, &amp;y1, &amp;x2, &amp;y2); map&lt;xy,int&gt; :: iterator it; if(m.find((xy){x1,y1}) == m.end()){ sum++; for(it = m.begin(); it != m.end(); it++) { int v = (*it).second; addEdge(sum,v,abs(x1-(*it).first.x) + abs(y1-(*it).first.y)); } m[(xy){x1,y1}] = sum; } if(m.find((xy){x2,y2}) == m.end()) { sum++; for(it = m.begin(); it != m.end(); it++) { int v = (*it).second; addEdge(sum,v,abs(x2-(*it).first.x) + abs(y2-(*it).first.y)); } m[(xy){x2,y2}] = sum; } int l = abs(x1-x2) + abs(y1-y2); addEdge(m[(xy){x1,y1}],m[(xy){x2,y2}],min(10,l)); } for(int i = 0; i &lt; 10; i++) ans[i] = 9999999999; ans[0] = 0; PriNodeQueue.push((Node){0,0}); while(!PriNodeQueue.empty()){ Node now = PriNodeQueue.top(); PriNodeQueue.pop(); int u = now.to; if(!isUsed[u]){ isUsed[u] = true; // printf(&#34;%d %d\n&#34;,u,ans[u]); for(int i = 0; i &lt; NodeQueue[u].size(); i++){ if(!isUsed[NodeQueue[u][i].to]){ int v = NodeQueue[u][i].to; int len = NodeQueue[u][i].len; if(ans[v] &gt; ans[u] + len) { ans[v] = ans[u] + len; PriNodeQueue.push((Node){v,ans[v]}); } } } } } printf(&#34;%lld&#34;,ans[1]); return 0; }

最短路径的裸题，用了nlogn的写法，优先队列，好久没写代码了，中间没bug出乎我的意料，以后每天一题不会落下，加油！
代码：
#include&lt;algorithm&gt; #include&lt;cmath&gt; #include&lt;queue&gt; #include&lt;vector&gt; using namespace std; struct Node { int to; long long len; bool operator&lt;(const Node &amp;a) const { return len &gt; a.len; } }; bool isUsed[510]; long long ans[510]; vector&lt;Node&gt; NodeQueue[510]; void addEdge(int s, int e, int len) { NodeQueue[s].push_back((Node){e,len}); NodeQueue[e].push_back((Node){s,len}); } int n,m; priority_queue&lt;Node&gt; PriNodeQueue; int main() { scanf(&#34;%d%d&#34;, &amp;n, &amp;m); while(m--) { int s, e, len; scanf(&#34;%d%d%d&#34;,&amp;s, &amp;e, &amp;len); if(s != e) addEdge(s, e, len); } int s, t; scanf(&#34;%d%d&#34;, &amp;s, &amp;t); for(int i = 0; i &lt; 505; i++) ans[i] = 999999999999; ans[s] = 0; PriNodeQueue.push((Node){s,0}); while(!PriNodeQueue.empty()){ Node now = PriNodeQueue.top(); PriNodeQueue.pop(); int u = now.to; if(!isUsed[u]){ isUsed[u] = true; for(int i = 0; i &lt; NodeQueue[u].size(); i++){ if(!isUsed[NodeQueue[u][i].to]){ int v = NodeQueue[u][i].to; int len = NodeQueue[u][i].len; if(ans[v] &gt; ans[u] + len) { ans[v] = ans[u] + len; PriNodeQueue.push((Node){v,ans[v]}); } } } } } printf(&#34;%lld&#34;,ans[t]); return 0; }

现在有一棵n个节点的树，节点1为这棵树的根，求出每个节点的深度以及每个节点的子树中的节点个数。
输入 第1行：一个数字n，表示树中节点的个数。(1&lt;=n&lt;=100000) 第2-n行：每行两个数字u,v，表示u与v之间有一条边。(1&lt;=u,v&lt;=n) 输出 输出n行，每行两个正整数，第i行的第一个正整数表示节点i的深度，第二个正整数表示以节点i为根的子树大小。
解法： 水题。。。。。太水了这个 代码：
#include&lt;algorithm&gt; using namespace std; int p[1010]; int sum[2010]; int a[1010]; int main() { int n; scanf(&#34;%d&#34;,&amp;n); for(int i = 0; i &lt; n; i++) { scanf(&#34;%d&#34;, &amp;a[i]); } int ans = 0; for(int i = n - 1; i &gt;= 0; i--){ if(a[i] == 0) continue; for(int j = a[i]; j &lt;=2005; j++) sum[j]++; for(int j = i - 1; j &gt;= 0; j--){ if(a[j] == 0) continue; int l = abs(a[i] - a[j]); int r = a[i] + a[j]; int s = sum[r - 1] - sum[l]; // printf(&#34;%d %d s: %d \n&#34;,sum[r-1],sum[l],s); if(a[i] &gt; l &amp;&amp; a[i] &lt; r) s--; // printf(&#34;%d %d %d\n&#34;,l,r,s); if(s &gt; 0) ans += s; } } printf(&#34;%d\n&#34;, ans); }

占坑。。。明天更。。。加油！！ ps:00:53点交一发 小b有一个仅包含非负整数的数组a，她想知道有多少个三元组(i,j,k)，满足i&lt;j&lt;k且a[i],a[j],a[k]可能作为某个三角形的三条边的边长。
输入 第一行输入一个正整数n，表示数组a中元素个数； 第二行n个非负整数，表示a中元素，以空格隔开； 其中0＜n≤1000，a中任意元素a[i]满足0≤a[i]≤1000。
输出 输出一个数，表示满足题意的三元组个数 输入样例 4 2 2 3 4 输出样例 3 解法：后缀记录一下每个数出现的次数，复杂度n^2，中间因为sum数组开小了wa了一发 代码：
#include&lt;algorithm&gt; using namespace std; int p[1010]; int sum[2010]; int a[1010]; int main() { int n; scanf(&#34;%d&#34;,&amp;n); for(int i = 0; i &lt; n; i++) { scanf(&#34;%d&#34;, &amp;a[i]); } int ans = 0; for(int i = n - 1; i &gt;= 0; i--){ if(a[i] == 0) continue; for(int j = a[i]; j &lt;=2005; j++) sum[j]++; for(int j = i - 1; j &gt;= 0; j--){ if(a[j] == 0) continue; int l = abs(a[i] - a[j]); int r = a[i] + a[j]; int s = sum[r - 1] - sum[l]; // printf(&#34;%d %d s: %d \n&#34;,sum[r-1],sum[l],s); if(a[i] &gt; l &amp;&amp; a[i] &lt; r) s--; // printf(&#34;%d %d %d\n&#34;,l,r,s); if(s &gt; 0) ans += s; } } printf(&#34;%d\n&#34;, ans); }

题目: 给出区间(a,b)，b &gt;= a，求𝑎 𝑥𝑜𝑟 (𝑎+1) 𝑥𝑜𝑟 (𝑎+2)&hellip;..𝑥𝑜𝑟 𝑏。 输入 输入2个数：a b，中间用空格分隔(1 &lt;= a &lt;= b &lt;= 10^9) 输出 输出一个答案 输入样例 3 8 输出样例 11
解法： 每个相邻的奇数与偶数xor之后的值是1，所以只要记录下a到b的长度，然后根据a的奇偶进行处理就可以了 代码：
#include&lt;stdlib.h&gt; #include&lt;cstring&gt; using namespace std; int f(int l) { l/=2; return l % 2; } int main() { int a,b; scanf(&#34;%d%d&#34;,&amp;a,&amp;b); int l = b - a + 1; //printf(&#34;l %d\n&#34;, l); int ans; //printf(&#34;%d\n&#34;,4) if(l &amp; 1) { if(a&amp;1) ans = a ^ (f(l - 1)); else ans = b ^ (f(l - 1)); } else { if(a&amp;1) ans = a^b^(f(l - 2)); else ans = f(l); } printf(&#34;%d&#34;, ans); return 0; } ps:好久没做题，一个水题想了好久

题目： 给定𝑛个技能，每个技能能打掉对手𝑎𝑖的血，你一共有𝑚次发招的机会，你不能连续使用某一个技能超过𝑘次。问你最多能打掉对手多少血。
输入 第一行3个数n,m,k，(2&lt;=n&lt;=2*10^5 ,1&lt;=m,k&lt;=10^9) 第二行n个数a[1&hellip;n]，(1&lt;=a[i]&lt;=10^9) 输出 一个数，表示最大值。
输入样例 6 9 2 1 3 3 7 4 2 输出样例 54 解法： 去top2，每次都是top1*k+top2,剩余的不足k就只去top1 代码：
#include&lt;algorithm&gt; using namespace std; int s[200010]; int main() { int n,m,k; scanf(&#34;%d%d%d&#34;, &amp;n, &amp;m, &amp;k); for(int i = 0; i &lt; n; i++) scanf(&#34;%d&#34;, &amp;s[i]); sort(s, s+n); int s1 = s[n - 1]; int s2 = s[n - 2]; long long p = s1*k + s2; long long ans = m/(k+1)*p + m%(k+1)*s1; printf(&#34;%lld\n&#34;,ans); }

题目: 输入一个长度为𝑛的数组𝑎，𝑎包括(𝑛−1)𝑛/2个区间。每个区间所有数的和，被称为区间和，求所有(𝑛−1)𝑛/2个区间和的和。由于数值较大，输出mod 1e9+7的结果。
输入 第一行一个整数n，表示数组长度(2&lt;=n&lt;=100000) 接下来n行，每行一个整数ai，表示数组的内容。(0&lt;=ai&lt;=50000) 输出 输出答案mod 1e9+7 输入样例 3 1 2 3 输出样例 20 解法： 统计每个数字出现的次数就好了，每个数字出现的次数为该数字左边数字的个数乘右边的。 代码：
using namespace std; int main() { long long ans = 0; long long mod = 1e9+7; long long n; scanf(&#34;%lld&#34;,&amp;n); long long e = n; for(int i = 1; i &lt;=n; i++,e--) { long long a; scanf(&#34;%lld&#34;, &amp;a); long long now = (((a*i)%mod) * e) % mod; ans = (ans + now) % mod; } printf(&#34;%lld&#34;, ans); return 0; }

