题目: 工厂里面，有n根待加工的铁棒，长度以米为单位，精确到小数点后两位（即厘米），现在市场上需求量是m根相同长度的铁棒。现在厂长想把这n根铁棒进行切割，切割的时候要精确到厘米，比如说，原来铁棒是1.00米的，那么可以切成0.50和0.50的，但是不能切成0.499和0.501的。并且不能将两根铁棒拼成一根铁棒。现在厂长想知道切出来的m根铁棒最长能有多长。
输入 单组测试数据。 第一行给出两个整数n(1 &lt;= n&lt;= 10000)和m(1 &lt;= m&lt; = 10000)。 接下来n行给出原始铁棒的长度L[1],L[2],L[3],&hellip;,L[n] ，(1&lt;=L[i]&lt;=100,000)。以米为单位，精确到小数点后两位。 输出 输出一个小数表示答案，精确到小数点后两位。 输入样例 样例输入1 4 11 8.02 7.43 4.57 5.39 输出样例 样例输出1 2.00 解法： 二分分情况讨论即可，因为题目有小数点限制，这里我直接*100 最后/100处理了这个情况 ps:(每天没时间刷题555555，选个一眼题找找手感，二分的边界情况还是有点乱，改天整理一下） 代码
using namespace std; int n,m; int a[100010]; bool c(int x) { if(x == 0) return true; long long sum = 0; for(int i = 0; i &lt; n; i++) sum += a[i]/x; return sum &gt;= m; } int main() { scanf(&#34;%d%d&#34;,&amp;n,&amp;m); for(int i = 0; i &lt; n; i++){ double s; scanf(&#34;%lf&#34;, &amp;s); a[i] = s*100; } int l = 1, r = 10000000; for(int i = 0; i &lt; 200; i++) { int m = (l+r)/2; if(c(m)) l = m; else r = m - 1; } if(c(r)) printf(&#34;%.2f\n&#34;,r*1.0/100); else printf(&#34;%.2f\n&#34;,l*1.0/100); return 0; }

题目： 有一个无限大的蜂巢迷宫，为了方便表示每一个六边形格子，现在把座标引入到这个迷宫中，如上图年示。
艾瑞特在这个迷宫中街，刚开始他在(0,0)的位置，按照下图所示的路线在这个迷宫中行走。 图片贴不上 这里附上原题目的链接： http://www.51nod.com/Challenge/Problem.html#problemId=1740
题解： 找规律即可（好久没刷题 太菜了 debug找了好久） 代码：
#include&lt;cmath&gt; #include&lt;algorithm&gt; using namespace std; int main() { long long n; scanf(&#34;%lld&#34;, &amp;n); if(n == 0) { printf(&#34;0 0&#34;); return 0; } // for(int i = 1; i &lt; 20; i++){ // n = i; n++; long long len = 1; long long sum = len; while(sum &lt; n) { sum += len*6; len++; } long long now = n -1 - (len - 1)*(len-2)*3; //printf(&#34;now %d\n&#34;,now); long long Time = now / (len - 1); now %= len - 1; long long x ,y; // printf(&#34;%d %d\n&#34;,Time, len); if(Time == 0) { x = 2 * (len - 1); y = 0; while(now--) x--,y+=2; } else if(Time == 1) { x = len - 1; y = 2*(len - 1); while(now--) x-=2; } else if(Time == 2) { x = 1 - len; y = 2*(len - 1); while(now--) x--,y-=2; } else if(Time == 3) { x = 2*(1-len); y = 0; while(now--) x++,y-=2; } else if(Time == 4) { x = 1-len; y = 2*(1 - len); while(now--) x+=2; } else if(Time == 5) { x = len - 1; y = 2*(1 - len); while(now--) x++,y+=2; } else { x = 2*(len - 1); y = 0; } printf(&#34;%lld %lld\n&#34;,x,y); // } return 0; }

今天周六，偷个懒选了个非常easy 的题目 题目： 有一个字符串S，下标从1开始，初始为S=&ldquo;0&rdquo;。现在开始调用fun函数。
{ for(i=0;i&lt;100000;i++) { tmp=change(S); S=S+&#34;0&#34;+tmp; } } change(s) { for(i=1;i&lt;=s.length();i++) { if(s[i]==&#39;0&#39;)s[i]=&#39;1&#39;; else s[i]=&#39;0&#39;; } i=1; j=s.length(); while(i&lt;=j) { tmp=s[i]; s[i]=s[j]; s[j]=tmp; i++; j--; } return s; } 现在有若干个查询，每一个查询有一个整数n，我们想知道字符串S第n位是什么。 解法： 通过找规律可以找到串是在每个2^n的地方都反对称的，所以进行递归进行处理即 可，2^n的位置即为0 代码:
#include&lt;cmath&gt; #include&lt;algorithm&gt; using namespace std; int solve(long long a, int flag) { if(a &lt;= 3) { if(a == 3) return abs(1 - flag); else return abs(0 - flag); } else { //printf(&#34;a %lld\n&#34;, a); int i = 0; long long p = a; while(p != 1){ p /= 2; i++; } long long now = 1; while(i--) now *= 2; if(now == a) return abs(0-flag); flag = abs(1 - flag); return solve(2 * now - a,flag); } } int main() { int t; scanf(&#34;%d&#34;, &amp;t); while(t--) { long long a; scanf(&#34;%lld&#34;, &amp;a); printf(&#34;%d\n&#34;, solve(a,0)); } return 0; }

题目： 又到了一年毕业季，Noder也从学校毕业了。现在Noder要把东西进行打包，打包完成后，Noder的所有东西都被装进了若干个长方体形状的收纳盒中，这些收纳盒的高都是1024，底座是正方形且边长都是1到6之间的整数。现在Noder要进行搬家了，他有一辆车，这个车子的后备箱是一个长方体，高为1024，底座为边长是6的正方形，那么Noder想知道，他最少要运几趟才能把他所有的东西运完呢？
解法： 题目还是比较容易理解的，矩形里面套矩形，怎么使得次数最少，分情况讨论即可（代码也太不简洁了）直接贴代码了😂😂 代码:
#include&lt;stdio.h&gt; #include&lt;iostream&gt; using namespace std; int a[7]; int main() { for(int i = 1; i &lt; 7; i++) scanf(&#34;%d&#34;, &amp;a[i]); int ans = 0; ans += (a[4] + a[5] + a[6]); a[1] -= a[5] * 11; a[5] = 0; if(a[1] &lt; 0) a[1] = 0; int p = a[2]/5; if(p &gt;= a[4]) { a[2] -= a[4]*5; a[4] = 0; } else { a[2] -= p*5; a[4] -= p; } if(a[4] &gt; 0) { if(a[1] &gt; 0) { a[1] -= 20-a[2]*4; a[2] = 0; a[4]--; a[1] -= a[4]*20; } else a[2]=0; if(a[1] &lt; 0) a[1] = 0; } //cout &lt;&lt;ans &lt;&lt;endl; //for(int i = 1; i &lt; 7; i++) // printf(&#34;%d %d
&#34;,i, a[i]); ans += a[3] / 4; a[3] = a[3] % 4; ans += a[2] / 9; a[2] = a[2] % 9; //cout &lt;&lt;ans &lt;&lt;endl; // for(int i = 1; i &lt; 7; i++) // printf(&#34;%d %d
&#34;,i, a[i]); // cout &lt;&lt; ans &lt;&lt;endl; if(a[3] == 0) { int sum = a[2] * 4 + a[1]; if(sum % 36 !=0) ans += sum/36 + 1; else ans += sum/36; } else if(a[3] == 1) { if(a[2] &gt;= 5) { a[2] -= 5; a[1] -= 7; if(a[1] &lt; 0) a[1] = 0; ans++; int sum = a[2] * 4 + a[1]; if(sum % 36 !=0) ans += sum/36 + 1; else ans += sum/36; } else { int sum = 27 - a[2] * 4; a[1] -= sum; if(a[1]&lt;0) a[1] = 0; ans++; if(a[1] % 36 != 0) ans += a[1]/36 +1; else ans += a[1]/36; } } else if(a[3] == 2) { if(a[2] &gt;= 3) { a[2] -=3; a[1] -= 6; if(a[1] &lt; 0) a[1] = 0; ans++; int sum = a[2] * 4 + a[1]; if(sum % 36 !=0) ans += sum/36 + 1; else ans += sum/36; } else { int sum = 18 - a[2] * 4; a[1] -= sum; if(a[1]&lt;0) a[1] = 0; ans++; if(a[1] % 36 != 0) ans += a[1]/36 +1; else ans += a[1]/36; } } else if(a[3] == 3) { if(a[2] &gt;= 1) { a[2] -= 1; a[1] -= 5; if(a[1] &lt; 0) a[1] = 0; ans++; int sum = a[2] * 4 + a[1]; if(sum % 36 !=0) ans += sum/36 + 1; else ans += sum/36; } else{ int sum = 9; a[1] -= sum; if(a[1]&lt;0) a[1] = 0; ans++; if(a[1] % 36 != 0) ans += a[1]/36 +1; else ans += a[1]/36; } } printf(&#34;%d
&#34;,ans); }

题目： 奥林匹克竞赛从1989年开始举行，每一个奥林匹克年都会有一个缩写IAO&rsquo;y， y表示那一年的最后几位数字。 组织者会取一个之前未被用过的缩写来表示该年份，而且要尽可能的短。
例如，前三个奥林匹克年是1989，1990和1991，他们对应的缩写是IAO'9， IAO'0 和IAO'1，而2015的缩写是IAO'15，因为IAO'5已经被1995用过了。
现在给出一个缩写，请判断这个是代表哪一年的。
多组测试数据。 输入 第一行有一个整数n (1≤n≤1000) ，表示要处理n组数据。 接下来n行，每一行有一个缩写。每一个缩写最多包含9位数字。 输出 对于每一个缩写，请输出对应的年份。 样例 5 IAO'15 IAO'2015 IAO'1 IAO'9 IAO'0
2015 12015 1991 1989 1990 做法： 经过思考并且打表找规律后。可以先预处理将位数比较小的数进行存储，用map映射即可，对于位数比较大的，全部预处理肯定不现实，规律如下：对于输入的每个数，数字的变化发生在1(*)3099处，举个例子，如果输入的是六位数，则113098之前的（包括113098），则ans为1113098，即之间在前面补1，如果大于等于113099，则直接输出，不用做任何处理。 代码
#include&lt;algorithm&gt; #include&lt;string&gt; #include&lt;cstring&gt; #include&lt;set&gt; #include&lt;map&gt; #include&lt;iostream&gt; using namespace std; map&lt;string, int&gt; m; set&lt;string&gt; s; int main() { for(int i = 1989; i &lt;= 100000; i++) { int p = i; string str = &#34;&#34;; string now = str + char(int(&#39;0&#39;)+ p%10); while(s.find(now) != s.end()) { p/=10; str = now; now = char(int(&#39;0&#39;)+ p%10) + str; } //cout&lt;&lt;now&lt;&lt;&#34; &#34;; s.insert(now); m[now] = i; //printf(&#34;%d\n&#34;,i); } int t; scanf(&#34;%d&#34;,&amp;t); char c; scanf(&#34;%c&#34;,&amp;c); //cout &lt;&lt; t &lt;&lt;endl; while(t--) { char a[10]; scanf(&#34;IAO\&#39;%s%c&#34;,a,&amp;c); //cout &lt;&lt; a &lt;&lt;endl; if(strlen(a) &lt;= 4) printf(&#34;%d\n&#34;, m[a]); else { int l = strlen(a); int rsum = (a[l-1] - &#39;0&#39;) + 10*(a[l-2]-&#39;0&#39;) + 100*(a[l-3]-&#39;0&#39;) + 1000*(a[l-4]-&#39;0&#39;); int now = 1; int p = l - 5; while(p--) { now = now * 10 + 1; } int lsum = 0; //cout &lt;&lt; &#34;p &#34;&lt;&lt;p&lt;&lt;endl; for(int i = 0; i &lt; l - 4; i++) lsum = lsum * 10 + (a[i] - &#39;0&#39;); // cout &lt;&lt; &#34;lsum rsum&#34;&lt;&lt;lsum&lt;&lt;&#34; &#34;&lt;&lt;rsum&lt;&lt;endl; if(lsum &lt; now) printf(&#34;1%s\n&#34;,a); else if(lsum == now &amp;&amp; rsum &lt; 3099) printf(&#34;1%s\n&#34;,a); else printf(&#34;%s\n&#34;,a); } } return 0; }

题目： 统计一下 𝑎𝑎𝑎 ⋯ 𝑎𝑎𝑎（𝑛个𝑎） × 𝑏 的结果里面有多少个数字d，a,b,d均为一位数。
样例解释：
3333333333*3=9999999999，里面有10个9。
解法： 打表可以得到，相乘的结果最多有4个不同的数字，如果n比较小暴力即可，如果n比较大的话，先求出这4个数字（可能有相同），然后根据n的大小得出。 结果的表示方法sl*re l可能有多位。
#include &lt;algorithm&gt; using namespace std; int main() { int t = 0; scanf(&#34;%d&#34;,&amp;t); while(t--) { int a,b,d,n; scanf(&#34;%d%d%d%d&#34;, &amp;a, &amp;b, &amp;d, &amp;n); if(n &lt; 5){ int now = 1; n--; while(n--) { now = now * 10 + 1; } int sum = a*now * b; int ans = 0; while(sum) { if(sum % 10 == d) ans++; sum /= 10; } printf(&#34;%d\n&#34;,ans); } else{ int num = a*11111*b; int now = a * b; int len; if(now &gt;= 10) len = 1; else len = 0; //printf(&#34;%d\n&#34;,num); int s,l,r,e; e = num % 10; num /= 10; r = num %10; num /= 10; l = num % 10; num /= 10; while(num &gt; 10) num /= 10; s = num; int sum = 0; if(d == s) sum++; if(d == r) sum++; if(d == l) sum += n-3+len; if(d == e) sum++; printf(&#34;%d\n&#34;,sum); } } return 0; }
